\begin{align}
d[(\nu_{b,t}-\lambda_b)Q^b_tB_{b,t}]
&=
Q^bB_b\nu_b\widehat\nu_{b,t}
\nonumber\\
&\quad
+Q^bB_b(\nu_b-\lambda_b)(q^b_t+b_{b,t}).
\label{eq:bgs-c71-bond-expansion}
\end{align}
